/**
 * Phase 9 — Typed factory dispatcher.
 *
 * Looks up a per-orbital factory by (organism, orbitalName) and calls
 * it with consumer params, narrowing from `object` to the per-factory
 * typed shape via emitted typed guards (no `as unknown as`).
 *
 * Autogenerated by scripts/regenerate-std-ts.mjs from
 * packages/almadar-std/behaviors/registry/<topic>/organisms/std-*.orb
 * (multi-orbital organisms only).
 *
 * @packageDocumentation
 */

import type { OrbitalDefinition, TraitReference } from '@almadar/core/types';


export interface ParamFieldDescriptor {
  name: string;
  type: string;
  description: string;
}

export interface OrbitalParamsManifest {
  organism: string;
  orbitalName: string;
  paramFields: readonly ParamFieldDescriptor[];
  traitNames: readonly string[];
  inlineTraitNames: readonly string[];
}

interface DispatchEntry {
  factory: (params: object) => OrbitalDefinition;
  manifest: OrbitalParamsManifest;
}

const REGISTRY: ReadonlyMap<string, DispatchEntry> = new Map<string, DispatchEntry>([
]);

/**
 * One trait reference appended via `params.extraTraits[]`. Phase 2
 * (Mechanism 2). `from` + `as` are required because the dispatcher
 * merges into `uses[]` verbatim — no JS-side name transforms.
 * Mirrors `ExtraTraitRef` from @almadar-io/agent — kept structural
 * (no inter-package type dep) but type-compatible.
 */
export interface DispatchExtraTrait
  extends Pick<TraitReference, 'ref' | 'name' | 'linkedEntity' | 'config' | 'events' | 'listens' | 'emitsScope'>
{
  from: string;
  as: string;
}

/**
 * Look up the per-orbital factory by (organism, orbitalName) and call
 * it with the supplied params. Returns null when no factory exists.
 * Throws TypeError when params fail the factory's typed guard
 * (caught by the agent's instantiate-orbital surface).
 *
 * `params.extraTraits` (Phase 2) is orthogonal to factory-specific
 * params: it's separated out BEFORE the typed guard runs and appended
 * to `def.traits[]` (with corresponding `uses[]` entries merged) AFTER
 * the factory returns. Strictly additive — never replaces factory
 * traits.
 */
export function dispatchOrbitalFactory(
  organism: string,
  orbitalName: string,
  params: object & { extraTraits?: DispatchExtraTrait[] },
): OrbitalDefinition | null {
  const entry = REGISTRY.get(`${organism}::${orbitalName}`);
  if (!entry) return null;
  const { extraTraits, ...factoryParams } = params;
  const def = entry.factory(factoryParams);
  if (extraTraits && extraTraits.length > 0) {
    if (!def.uses) def.uses = [];
    if (!def.traits) def.traits = [];
    for (const extra of extraTraits) {
      // Dedup on alias (`as`), not registry path (`from`). Multiple
      // aliases for the same path are valid: the factory may have
      // already imported `from: std-stats as: Stats`, but a caller
      // appending `from: std-stats as: KpiStats` needs the new
      // alias registered so its `ref: KpiStats.traits.…` resolves.
      const aliasTaken = def.uses.some((u) => u.as === extra.as);
      if (!aliasTaken) {
        def.uses.push({ from: extra.from, as: extra.as });
      }
      const { from: _from, as: _as, ...traitFields } = extra;
      def.traits.push(traitFields);
    }
  }
  return def;
}

/**
 * Fetch the params manifest for one (organism, orbitalName). Returns
 * null when no factory exists. Used by the agent's Stage A prompt to
 * surface paramFields + traitNames + inlineTraitNames as the closed
 * set the LLM may emit.
 */
export function getOrbitalFactoryManifest(
  organism: string,
  orbitalName: string,
): OrbitalParamsManifest | null {
  const entry = REGISTRY.get(`${organism}::${orbitalName}`);
  return entry ? entry.manifest : null;
}

/**
 * List every orbital manifest for one organism. Used by Stage A to
 * embed the chosen organism's full manifest set into the prompt.
 */
export function listOrganismOrbitalManifests(
  organism: string,
): OrbitalParamsManifest[] {
  const out: OrbitalParamsManifest[] = [];
  const prefix = `${organism}::`;
  for (const [key, entry] of REGISTRY) {
    if (key.startsWith(prefix)) out.push(entry.manifest);
  }
  return out;
}
